import React, { useState } from 'react'
import { useNavigate } from 'react-router-dom'
import { useForm } from 'react-hook-form'
import API from '../lib/api.js'
import bannerLogin from '../assets/banner-login.png'
import logoTB from '../assets/Logo-TB.png'


function Login({ setUser }) {
  const navigate = useNavigate()
  const { register, handleSubmit, formState: { isSubmitting } } = useForm()
  const imageUrl = bannerLogin
  const [error, setError] = useState(null)

  const onSubmit = async (data) => {
    try {
      const res = await API.post('/auth/login', data)
      localStorage.setItem('token', res.data.token)
      localStorage.setItem('user', JSON.stringify(res.data.user))
      try {
        for (let i = localStorage.length - 1; i >= 0; i--) {
          const k = localStorage.key(i) || ''
          if (k && k.startsWith('tbMastersCache')) localStorage.removeItem(k)
        }
      } catch {}
      setUser(res.data.user)
      navigate('/panel')
    } catch (e) {
      const msg = e.response?.data?.error || e.message || 'Error desconocido'
      setError('Login falló: ' + msg)
    }
  }

  const LoginHero = React.memo(function LoginHero({ imageUrl }) {
    return (
      <div className="login-image" style={{ backgroundImage: `url(${imageUrl})` }}>
        <div className="login-overlay">
          <div className="login-overlay-content">
            <h2 className="h2" style={{ color: '#fff', marginBottom: '8px' }}>Reporte fotográfico</h2>
            <p className="muted" style={{ color: '#e5e7eb' }}>Toma y sube evidencias de tus HBLs.</p>
          </div>
        </div>
      </div>
    )
  })

  return (
    <div className="login-grid">
      <LoginHero imageUrl={imageUrl} />
      <div className="card login-card">
        <div className="login-card-content">
          <img className="login-logo" src={logoTB} alt="Logística ágil" />
        </div>
        <h1 className="h1">Bienvenido</h1>
        <p className="muted">Introduce tu email y contraseña para acceder.</p>
        <form onSubmit={handleSubmit(onSubmit)} className="form">
          <label className="label">
            Email
            <input className="input" type="email" placeholder="usuario@transborder.com.co" {...register('email', { required: true })} />
          </label>
          <label className="label">
            Password
            <input className="input" type="password" placeholder="contraseña" {...register('password', { required: true })} />
          </label>
          <button className="btn btn-primary" disabled={isSubmitting}>{isSubmitting ? 'Cargando...' : 'Entrar'}</button>
          {error && <div className="error">{error}</div>}
        </form>
      </div>
      {isSubmitting && (
        <div className="loading-backdrop" aria-live="polite" aria-busy="true">
          <div className="loading-spinner"></div>
          <div className="loading-text">Cargando...</div>
        </div>
      )}
    </div>
  )
}

export default Login
